import React, { useState, useEffect } from "react";
import { Menu, X, Globe } from "lucide-react"; // ضفنا أيقونة الكرة الأرضية
import { Link, useLocation } from "react-router-dom";
import { useTranslation } from "react-i18next"; // استيراد الـ Hook
import "./navbar.css";

export default function Header() {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();
  const { t, i18n } = useTranslation(); // استخراج دالة الترجمة t ودالة التحكم باللغة i18n

  // مصفوفة الروابط باستخدام مفاتيح الترجمة (نفس المفاتيح اللي بملف i18n.js)
  const NAV_LINKS = [
    { label: t("nav_home"), to: "/" },
    { label: t("nav_about"), to: "/AboutUs" },
    { label: t("nav_products"), to: "/Products" },
    { label: t("nav_contact"), to: "/ContactUs" },
  ];

  const closeMenu = () => setIsOpen(false);

  // دالة تبديل اللغة
  const toggleLanguage = () => {
    const newLang = i18n.language === "ar" ? "en" : "ar";
    i18n.changeLanguage(newLang);
  };

  // مراقبة تغيير اللغة لتعديل اتجاه الصفحة (RTL / LTR) تلقائياً
  useEffect(() => {
    document.body.dir = i18n.dir();
  }, [i18n.language]);

  return (
    <nav className="navbar">
      <div className="navbar-container">
        {/* الروابط وأزرار التحكم */}
        <div className="navbar-links-wrapper">
          <div className="navbar-links desktop-only">
            {NAV_LINKS.map((link) => (
              <Link
                key={link.to}
                to={link.to}
                className={`nav-link ${
                  location.pathname === link.to ? "active" : ""
                }`}
              >
                {link.label}
              </Link>
            ))}

            {/* زر تبديل اللغة للديسكتوب */}
            <button onClick={toggleLanguage} className="lang-switch-btn">
              <Globe size={18} />
              <span>{i18n.language === "ar" ? "English" : "العربية"}</span>
            </button>
          </div>

          {/* Mobile Menu Button */}
          <div className="mobile-only flex items-center">
            {/* زر تبديل اللغة للموبايل يظهر بجانب القائمة */}
            <button onClick={toggleLanguage} className="lang-switch-btn-mobile">
              {i18n.language === "ar" ? "EN" : "AR"}
            </button>
            <button onClick={() => setIsOpen(!isOpen)} className="menu-toggle">
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>

        {/* اللوجو */}
        <div className="navbar-logo-wrapper">
          <Link to="/" className="logo flex">
            <img className="navImage" src="/images/final.webp" alt="Biscoza" />
          </Link>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="mobile-menu">
          {NAV_LINKS.map((link) => (
            <Link
              key={link.to}
              to={link.to}
              className={`mobile-nav-link ${
                location.pathname === link.to ? "active" : ""
              }`}
              onClick={closeMenu}
            >
              {link.label}
            </Link>
          ))}
        </div>
      )}
    </nav>
  );
}
